import{_ as r,C as d,o as e,c as i,a2 as l,b as s,w as a,a as o,E as h,a3 as f}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"主题索引","description":"","frontmatter":{},"headers":[],"relativePath":"02_concepts/index.md","filePath":"02_concepts/index.md"}'),g={name:"02_concepts/index.md"};function c(E,t,x,y,A,p){const n=d("Mermaid");return e(),i("div",null,[t[1]||(t[1]=l('<h1 id="主题索引" tabindex="-1">主题索引 <a class="header-anchor" href="#主题索引" aria-label="Permalink to &quot;主题索引&quot;">​</a></h1><p>按主题分类阅读巴菲特致股东信的核心思想，提炼70年投资智慧的精华。</p><hr><h2 id="投资哲学" tabindex="-1">投资哲学 <a class="header-anchor" href="#投资哲学" aria-label="Permalink to &quot;投资哲学&quot;">​</a></h2><p>投资哲学是巴菲特思想体系的根基。这四个概念构成了价值投资的完整框架：<strong>内在价值</strong>告诉你买什么，<strong>护城河</strong>帮你识别好生意，<strong>安全边际</strong>保护你不亏钱，<strong>复利</strong>让时间为你工作。</p><table tabindex="0"><thead><tr><th style="text-align:left;">主题</th><th style="text-align:left;">核心要义</th><th style="text-align:left;">必读年份</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/02_concepts/intrinsic-value.html">内在价值 Intrinsic Value</a></td><td style="text-align:left;">企业真正值多少钱</td><td style="text-align:left;">1994, 2000, 2007, 2008</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/moat.html">护城河 Moat</a></td><td style="text-align:left;">竞争优势的宽度与持久度</td><td style="text-align:left;">1993, 1999, 2007, 2014</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/safety-margin.html">安全边际 Margin of Safety</a></td><td style="text-align:left;">用折扣价格买好资产</td><td style="text-align:left;">1997, 2007, 2008, 2020</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/compounding.html">复利 Compounding</a></td><td style="text-align:left;">时间是伟大事业的朋友</td><td style="text-align:left;">1965, 1993, 2013, 2023</td></tr></tbody></table><h2 id="业务分析" tabindex="-1">业务分析 <a class="header-anchor" href="#业务分析" aria-label="Permalink to &quot;业务分析&quot;">​</a></h2><p>伯克希尔不是一家普通公司，而是一个复杂的业务帝国。理解保险浮存金、承保纪律和资本配置，才能看懂伯克希尔独特的商业模式。</p><table tabindex="0"><thead><tr><th style="text-align:left;">主题</th><th style="text-align:left;">核心要义</th><th style="text-align:left;">必读年份</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/02_concepts/insurance-float.html">保险浮存金 Insurance Float</a></td><td style="text-align:left;">伯克希尔的秘密引擎</td><td style="text-align:left;">1967, 2005, 2006, 2010</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/underwriting-discipline.html">承保纪律 Underwriting Discipline</a></td><td style="text-align:left;">不做价格战，守住底线</td><td style="text-align:left;">2001, 2004, 2017</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/capital-allocation.html">资本配置 Capital Allocation</a></td><td style="text-align:left;">把每一分钱用在刀刃上</td><td style="text-align:left;">1983, 2012, 2020</td></tr></tbody></table><h2 id="思维方法" tabindex="-1">思维方法 <a class="header-anchor" href="#思维方法" aria-label="Permalink to &quot;思维方法&quot;">​</a></h2><p>投资是一场思维方式的较量。知道自己懂什么、保持独立思考、理解真正的风险——这些是巴菲特区别于普通投资者的核心能力。</p><table tabindex="0"><thead><tr><th style="text-align:left;">主题</th><th style="text-align:left;">核心要义</th><th style="text-align:left;">必读年份</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/02_concepts/circle-of-competence.html">能力圈 Circle of Competence</a></td><td style="text-align:left;">知道边界比知道多少更重要</td><td style="text-align:left;">1996, 1999, 2000, 2017</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/contrarian.html">逆向思维 Contrarian Thinking</a></td><td style="text-align:left;">别人恐惧时贪婪</td><td style="text-align:left;">1987, 2008, 2009, 2020</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/risk.html">风险与回报 Risk &amp; Return</a></td><td style="text-align:left;">永久损失才是风险</td><td style="text-align:left;">1993, 2003, 2007, 2008</td></tr></tbody></table><h2 id="人生智慧" tabindex="-1">人生智慧 <a class="header-anchor" href="#人生智慧" aria-label="Permalink to &quot;人生智慧&quot;">​</a></h2><p>投资最终是关于人的事业。选择德才兼备的管理者、坚守诚信、用长期视角看待世界——这些人生智慧贯穿于巴菲特70年的投资生涯。</p><table tabindex="0"><thead><tr><th style="text-align:left;">主题</th><th style="text-align:left;">核心要义</th><th style="text-align:left;">必读年份</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/02_concepts/reputation.html">声誉 Reputation</a></td><td style="text-align:left;">建立需20年，毁掉只需5分钟</td><td style="text-align:left;">1991, 2014, 2020</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/management.html">管理层选择 Management</a></td><td style="text-align:left;">找到对的船长</td><td style="text-align:left;">1983, 1995, 2005, 2015</td></tr><tr><td style="text-align:left;"><a href="/02_concepts/long-term.html">长期主义 Long-term Thinking</a></td><td style="text-align:left;">不想持十年就别持十分钟</td><td style="text-align:left;">1996, 2001, 2013, 2020</td></tr></tbody></table><hr><h2 id="主题关联图" tabindex="-1">主题关联图 <a class="header-anchor" href="#主题关联图" aria-label="Permalink to &quot;主题关联图&quot;">​</a></h2>',17)),(e(),s(f,null,{default:a(()=>[h(n,{id:"mermaid-246",class:"mermaid",graph:"mindmap%0A%20%20root((%E4%BB%B7%E5%80%BC%E6%8A%95%E8%B5%84))%0A%20%20%20%20%E6%8A%95%E8%B5%84%E5%93%B2%E5%AD%A6%0A%20%20%20%20%20%20%E5%86%85%E5%9C%A8%E4%BB%B7%E5%80%BC%0A%20%20%20%20%20%20%E6%8A%A4%E5%9F%8E%E6%B2%B3%0A%20%20%20%20%20%20%E5%AE%89%E5%85%A8%E8%BE%B9%E9%99%85%0A%20%20%20%20%20%20%E5%A4%8D%E5%88%A9%0A%20%20%20%20%E4%B8%9A%E5%8A%A1%E5%88%86%E6%9E%90%0A%20%20%20%20%20%20%E6%B5%AE%E5%AD%98%E9%87%91%0A%20%20%20%20%20%20%E6%89%BF%E4%BF%9D%E7%BA%AA%E5%BE%8B%0A%20%20%20%20%20%20%E8%B5%84%E6%9C%AC%E9%85%8D%E7%BD%AE%0A%20%20%20%20%E6%80%9D%E7%BB%B4%E6%96%B9%E6%B3%95%0A%20%20%20%20%20%20%E8%83%BD%E5%8A%9B%E5%9C%88%0A%20%20%20%20%20%20%E9%80%86%E5%90%91%E6%80%9D%E7%BB%B4%0A%20%20%20%20%20%20%E9%A3%8E%E9%99%A9%0A%20%20%20%20%E4%BA%BA%E7%94%9F%E6%99%BA%E6%85%A7%0A%20%20%20%20%20%20%E5%A3%B0%E8%AA%89%0A%20%20%20%20%20%20%E7%AE%A1%E7%90%86%E5%B1%82%0A%20%20%20%20%20%20%E9%95%BF%E6%9C%9F%E4%B8%BB%E4%B9%89%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[o(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=l("<hr><blockquote><p>💡 <strong>学习建议</strong></p><ol><li><strong>按顺序阅读</strong>：建议从&quot;投资哲学&quot;四个主题开始，建立完整的价值投资框架</li><li><strong>结合原文</strong>：每个主题页面都标注了重点年份，建议结合对应年份的股东信阅读</li><li><strong>交叉验证</strong>：主题之间存在内在联系，如护城河决定复利质量，安全边际保护复利不受中断</li><li><strong>长期反复</strong>：这些主题值得在不同市场环境下反复阅读，每次都会有新的体会</li></ol></blockquote>",2))])}const B=r(g,[["render",c]]);export{_ as __pageData,B as default};
